const dictionaries = { en, de, ar } as const;

function interpolate(template: string, values?: Record<string, string | number>) {
  if (!values) return template;
  return Object.entries(values).reduce((result, [key, value]) => result.replaceAll(`{${key}}`, String(value)), template);
}

export function translateTrain(language: SupportedLanguage, key: TrainKey, values?: Record<string, string | number>) {
  return interpolate(dictionaries[language][key] ?? en[key], values);
}

export function getTrainLocaleMetadata(language: SupportedLanguage) {
  return {
    dir: (language === "ar" ? "rtl" : "ltr") as "ltr" | "rtl",
    locale: language === "de" ? "de-DE" : language === "ar" ? "ar" : "en-US"
  };
}

export function useTrainTranslation() {
  const { language } = useTranslation();
  const { dir, locale } = getTrainLocaleMetadata(language);
  const tr = useCallback((key: TrainKey, values?: Record<string, string | number>) => translateTrain(language, key, values), [language]);
  return { language, dir, locale, tr };
}
